mapper.select:
select qp.id, qp.title, qp.quality_standard, qp.acceptance_rule, qp.owner_id, u.real_name as owner_name, qp.status, qp.created_at, qp.updated_at from quality_plan qp left join sys_user u on u.id = qp.owner_id where qp.project_id = #{projectId} and qp.is_deleted = 0
and qp.status = #{query.status}
and qp.owner_id = #{query.ownerId}
order by qp.updated_at desc, qp.created_at desc

mapper.insert:
insert into quality_plan (
    id, project_id, title, quality_standard, acceptance_rule, owner_id, status, created_at, updated_at, is_deleted
) values (
    #{id}, #{projectId}, #{title}, #{qualityStandard}, #{acceptanceRule}, #{ownerId}, #{status}, #{createdAt}, #{updatedAt}, #{deleted}
)

mapper.update:
update quality_plan
set title = #{title},
    quality_standard = #{qualityStandard},
    acceptance_rule = #{acceptanceRule},
    owner_id = #{ownerId},
    status = #{status},
    updated_at = #{updatedAt}
where project_id = #{projectId}
  and id = #{id}
  and is_deleted = 0

update quality_plan
set is_deleted = 1
where project_id = #{projectId}
  and id = #{id}
  and is_deleted = 0

mapper.select:
select count(1)
from quality_activity
where project_id = #{projectId}
  and quality_plan_id = #{qualityPlanId}
  and is_deleted = 0

select qa.id, qa.quality_plan_id, qp.title as quality_plan_title, qa.activity_name, qa.activity_type, qa.planned_date, qa.actual_date, qa.result, qa.owner_id, u.real_name as owner_name, qa.created_at, qa.updated_at from quality_activity qa left join quality_plan qp on qp.id = qa.quality_plan_id left join sys_user u on u.id = qa.owner_id where qa.project_id = #{projectId} and qa.is_deleted = 0
and qa.quality_plan_id = #{query.qualityPlanId}
and qa.activity_type = #{query.activityType}
and qa.owner_id = #{query.ownerId}
order by qa.planned_date desc, qa.created_at desc

mapper.insert:
insert into quality_activity (
    id, project_id, quality_plan_id, activity_name, activity_type, planned_date, actual_date, result, owner_id, created_at, updated_at, is_deleted
) values (
    #{id}, #{projectId}, #{qualityPlanId}, #{activityName}, #{activityType}, #{plannedDate}, #{actualDate}, #{result}, #{ownerId}, #{createdAt}, #{updatedAt}, #{deleted}
)

mapper.update:
update quality_activity
set is_deleted = 1
where project_id = #{projectId}
  and id = #{id}
  and is_deleted = 0

mapper.select:
select id, metric_name, metric_value, metric_unit, statistic_date, created_at from quality_metric where project_id = #{projectId}
and metric_name like concat('%', #{query.metricName}, '%')
order by statistic_date desc, created_at desc

mapper.insert:
insert into quality_metric (
    id, project_id, metric_name, metric_value, metric_unit, statistic_date, created_at
) values (
    #{id}, #{projectId}, #{metricName}, #{metricValue}, #{metricUnit}, #{statisticDate}, #{createdAt}
)

mapper.update:
update quality_metric
set metric_name = #{metricName},
    metric_value = #{metricValue},
    metric_unit = #{metricUnit},
    statistic_date = #{statisticDate}
where project_id = #{projectId}
  and id = #{id}

mapper.delete:
delete from quality_metric
where project_id = #{projectId}
  and id = #{id}
